INSERT INTO `chathistories` VALUES (37,'Merhaba','user','2025-05-12 12:15:46','2025-05-12 12:15:46',1),(38,'Merhaba! Ben İngilizce öğretmenin ve öğrenme koçun. Seninle İngilizce öğrenme sürecinde yardımcı olmak için buradayım. Eğer İngilizce seviyeni geliştirmek istiyorsan, dersler alabilir, quizler çözebilir, rozetler kazanabilir ve pratik yapabilirsin. Seyahat amacın varsa, günlük pratiklerle bu konuda sana destek olabilirim. Sana nasıl yardımcı olabileceğimi veya soruların varsa nasıl cevaplayabileceğimi söyleyebilirsin. Başlamak için bir ders almak ister misin? 😊🌟','bot','2025-05-12 12:15:46','2025-05-12 12:15:46',1),(39,'merhaba','user','2025-05-12 12:24:06','2025-05-12 12:24:06',1),(40,'Merhaba! Nasıl yardımcı olabilirim bugün? İngilizce öğrenme sürecinde nerede olduğunu ve ne yapmak istediğini bana anlatır mısın? 😊🚀','bot','2025-05-12 12:24:06','2025-05-12 12:24:06',1),(41,'önceki mesajımda ne yazdım','user','2025-05-12 12:25:36','2025-05-12 12:25:36',1),(42,'Önceki mesajında sadece \"Merhaba\" yazmıştın. Nasıl yardımcı olabileceğimi veya ne yapmak istediğini bana anlatmak ister misin? 😊🌟','bot','2025-05-12 12:25:36','2025-05-12 12:25:36',1),(43,'Merhaba öğretmenim, bugünkü dersime nasıl devam etmeliyim?','user','2025-05-17 15:35:51','2025-05-17 15:35:51',1),(44,'Önceki mesajında \"Merhaba öğretmenim, bugünkü dersime nasıl devam etmeliyim?\" yazmıştın. Bugün hangi konuları çalışmak istediğini veya hangi konular üzerinde daha fazla pratik yapmak istediğini bana söyleyebilirsin. Seninle İngilizce öğrenme sürecinde yardımcı olmak için buradayım. Ne yapmak istediğini bana anlatmaktan çekinme! 😊📚','bot','2025-05-17 15:35:51','2025-05-17 15:35:51',1),(45,'Biraz ders çalışmak istiyorum','user','2025-05-17 15:36:12','2025-05-17 15:36:12',1),(46,'Harika! Ders çalışmaya devam etmek için önerilerim var. Bugün A2 seviyesinde olduğunu ve seyahat amacın olduğunu biliyorum. Bu bağlamda, seyahatle ilgili temel ifadeleri ve kalıpları tekrar etmek faydalı olabilir. Örneğin:\n- Havaalanında yönlendirme ifadeleri: \"Where is the check-in counter?\" (Check-in kontuarı nerede?)\n- Otel rezervasyonu: \"I have a reservation under the name of John Smith.\" (John Smith adına bir rezervasyonum var.)\n- Restoranda sipariş verme: \"I would like to order a local dish, please.\" (Lütfen yerel bir yemek sipariş etmek istiyorum.)\n\nBu ifadeleri tekrar etmek ve örnek cümlelerle pratik yapmak ders çalışmana yardımcı olabilir. İstediğin bir konu veya konuyla ilgili özel bir sorun varsa bana söyleyebilirsin. Şimdi ders çalışmaya başlamak için bir konu seç veya üzerinde çalışmak istediğin bir şey var mı? 😊📚🌟','bot','2025-05-17 15:36:12','2025-05-17 15:36:12',1),(47,'Selam en son hangi quizi çözdüm?','user','2025-05-27 03:16:15','2025-05-27 03:16:15',1),(48,'En son çözdüğün quiz \"A1 - Demo Quiz\" idi. Bu quizi başarıyla tamamladın! Eğer başka bir konuda daha pratik yapmak istersen veya farklı bir quiz çözmek istersen bana söyleyebilirsin. Sana hangi konuda çalışmak istediğin konusunda yardımcı olabilirim. Ders çalışmaya devam etmek için kararlılığını takdir ediyorum! Başarılar! 🌟📚','bot','2025-05-27 03:16:15','2025-05-27 03:16:15',1),(49,'En son tamamladığım ders hangisiydi','user','2025-05-27 03:19:10','2025-05-27 03:19:10',1),(50,'Son etkinliğin \"A1 – Genel Okuma Pratiği\" dersini tamamlamışsın. Eğer bu konuda daha fazla pratik yapmak veya farklı bir konu üzerinde çalışmak istersen, ben buradayım. Sana yardımcı olmak için hazırım! Başarılarının devamını dilerim. 😊📖🌟','bot','2025-05-27 03:19:10','2025-05-27 03:19:10',1),(51,'Tamam','user','2025-05-27 03:34:15','2025-05-27 03:34:15',1),(52,'Eğer başka bir sorunuz veya yardıma ihtiyacınız varsa çekinmeden bana sorabilirsiniz. İyi günler! 😊🌟📚\n\n(Son Aktiviteler: [point] quiz_completed, [point] perfect_quiz, [badge] İlk Quiz Rozeti, [point] quiz_completed, [point] perfect_quiz)','bot','2025-05-27 03:34:15','2025-05-27 03:34:15',1),(53,'Selam','user','2025-05-27 03:39:49','2025-05-27 03:39:49',1),(54,'Merhaba! Nasıl yardımcı olabilirim bugün? Eğer ders çalışmak veya pratik yapmak istersen, konuşmaktan çekinme. 😊📚🌟\n\n(Son Aktiviteler: [quiz] A1 - Alfabe, Selamlaşma ve Tanışma Quiz, [point] quiz_completed, [lesson] A1- Yiyecekler ve İçecekler, [lesson] A1 - Zamirler, [lesson] A1 - Alfabe, Selamlaşma ve Tanışma, [badge] Ders Ustası, [point] lesson_completed, [point] lesson_completed, [point] lesson_completed, [point] lesson_completed, [point] lesson_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] perfect_quiz, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [badge] Quiz Ustası, [badge] Mükemmeliyetçi, [point] quiz_completed, [point] perfect_quiz, [point] quiz_completed, [point] quiz_completed, [point] quiz_completed, [point] perfect_quiz, [badge] İlk Quiz Rozeti, [point] quiz_completed, [point] perfect_quiz)','bot','2025-05-27 03:39:49','2025-05-27 03:39:49',1),(55,'en son çözdüğüm ders neydi','user','2025-05-27 03:40:35','2025-05-27 03:40:35',1),(56,'Son dersiniz \"A1 - Alfabe, Selamlaşma ve Tanışma\" dersiydi. Eğer bu konuda daha fazla pratik yapmak isterseniz veya farklı bir konu üzerinde çalışmak isterseniz, size yardımcı olmaktan mutluluk duyarım. Herhangi bir sorunuz varsa çekinmeden bana sorabilirsiniz. Başarılar dilerim! 😊📚🌟\n\n(Son Aktiviteler: [quiz] A1 - Alfabe, Selamlaşma ve Tanışma Quiz, [point] quiz_completed, [lesson] A1- Yiyecekler ve İçecekler, [lesson] A1 - Zamirler, [lesson] A1 - Alfabe, Selamlaşma ve Tanışma, [badge] Ders Ustası, [point] lesson_completed, [point] lesson_completed, [point] lesson_completed, [point] lesson_completed, 