INSERT INTO `lessonpages` VALUES (12,5,1,'info','\"{\\n  \\\"type\\\": \\\"text\\\",\\n  \\\"content\\\": {\\n    \\\"title\\\": \\\"İngilizce Alfabeye Giriş\\\",\\n    \\\"body\\\": \\\"İngilizce alfabede toplam 26 harf bulunur. Bu harflerin her birinin büyük (A, B, C...) ve küçük (a, b, c...) hali vardır. İngilizce öğrenirken bu harfleri okumak, yazmak ve telaffuz etmek çok önemlidir.\\\\n\\\\nBazı harflerin okunuşu Türkçedeki harflerden farklıdır. Bu nedenle alfabeyi öğrenirken hem harfin şeklini hem de sesini tanımak gerekir.\\\\n\\\\nAşağıda İngilizce alfabedeki harflerin büyük ve küçük yazımı ile birlikte okunuşlarını gösteren tabloyu inceleyebilirsin.\\\",\\n    \\\"imageUrl\\\": \\\"/images/alfabe.png\\\"\\n  }\\n}\"','2025-05-26 10:08:11','2025-05-26 10:08:11'),(13,5,2,'listen','\"{\\n  \\\"type\\\": \\\"listen\\\",\\n  \\\"content\\\": {\\n    \\\"audioUrl\\\": \\\"/audio/a.mp3\\\",\\n    \\\"question\\\": \\\"Dinlediğin harf hangisidir?\\\",\\n    \\\"options\\\": [\\\"A\\\", \\\"E\\\", \\\"I\\\", \\\"Y\\\"],\\n    \\\"correctAnswer\\\": \\\"A\\\"\\n  }\\n}\"','2025-05-26 10:31:45','2025-05-26 10:31:45'),(14,5,1,'image','\"{\\n  \\\"type\\\": \\\"image\\\",\\n  \\\"content\\\": {\\n    \\\"imageUrl\\\": \\\"/images/apple.jpg\\\",\\n    \\\"question\\\": \\\"Bu görsel hangi harf ile başlıyor?\\\",\\n    \\\"options\\\": [\\\"A\\\", \\\"R\\\", \\\"P\\\", \\\"E\\\"],\\n    \\\"correctAnswer\\\": \\\"A\\\"\\n  }\\n}\"','2025-05-26 10:37:58','2025-05-26 10:37:58'),(15,5,3,'image','\"{\\n  \\\"type\\\": \\\"image\\\",\\n  \\\"content\\\": {\\n    \\\"imageUrl\\\": \\\"/images/apple.jpg\\\",\\n    \\\"question\\\": \\\"Bu görsel hangi harf ile başlıyor?\\\",\\n    \\\"options\\\": [\\\"A\\\", \\\"B\\\", \\\"C\\\", \\\"D\\\"],\\n    \\\"correctAnswer\\\": \\\"A\\\"\\n  }\\n}\"','2025-05-26 10:38:29','2025-05-26 10:38:29'),(16,5,4,'listen','\"{\\n  \\\"type\\\": \\\"listen\\\",\\n  \\\"content\\\": {\\n    \\\"audioUrl\\\": \\\"/audio/i.mp3\\\",\\n    \\\"question\\\": \\\"Dinlediğin harf hangisidir?\\\",\\n    \\\"options\\\": [\\\"E\\\", \\\"I\\\", \\\"A\\\", \\\"U\\\"],\\n    \\\"correctAnswer\\\": \\\"I\\\"\\n  }\\n}\"','2025-05-26 10:42:25','2025-05-26 10:42:25'),(23,5,5,'info','\"{\\n  \\\"type\\\": \\\"text\\\",\\n  \\\"content\\\": {\\n    \\\"title\\\": \\\"Selamlaşma Kalıpları\\\",\\n    \\\"body\\\": \\\"İngilizce\'de insanlar günün farklı saatlerinde veya farklı durumlarda selamlaşmak için çeşitli ifadeler kullanırlar.\\\",\\n    \\\"imageUrl\\\": \\\"/images/greetings.png\\\",\\n    \\\"imageClass\\\": \\\"max-h-[500px] md:max-h-[700px]\\\"\\n  }\\n}\"','2025-05-26 11:06:25','2025-05-26 11:06:25'),(24,5,6,'match','\"{\\n  \\\"type\\\": \\\"match\\\",\\n  \\\"content\\\": {\\n    \\\"pairs\\\": [\\n      { \\\"left\\\": \\\"Hello\\\", \\\"right\\\": \\\"Merhaba\\\" },\\n      { \\\"left\\\": \\\"Hi\\\", \\\"right\\\": \\\"Selam\\\" },\\n      { \\\"left\\\": \\\"Good morning\\\", \\\"right\\\": \\\"Günaydın\\\" },\\n      { \\\"left\\\": \\\"Good evening\\\", \\\"right\\\": \\\"İyi akşamlar\\\" },\\n      { \\\"left\\\": \\\"How are you?\\\", \\\"right\\\": \\\"Nasılsın?\\\" }\\n    ]\\n  }\\n}\"','2025-05-26 11:12:46','2025-05-26 11:12:46'),(25,5,7,'reorder','\"{\\n  \\\"type\\\": \\\"reorder\\\",\\n  \\\"content\\\": {\\n    \\\"instruction\\\": \\\"Kelimeleri doğru sıraya koyarak bir tanışma sorusu oluştur.\\\",\\n    \\\"words\\\": [\\\"you\\\", \\\"do\\\", \\\"do\\\", \\\"for\\\", \\\"living\\\", \\\"a\\\", \\\"What\\\"],\\n    \\\"correctOrder\\\": [\\\"What\\\", \\\"do\\\", \\\"you\\\", \\\"do\\\", \\\"for\\\", \\\"a\\\", \\\"living\\\"]\\n  }\\n}\"','2025-05-26 11:24:34','2025-05-26 11:24:34'),(26,5,8,'fill','\"{\\n  \\\"type\\\": \\\"fill\\\",\\n  \\\"content\\\": {\\n    \\\"sentence\\\": \\\"Nice to ___ you!\\\",\\n    \\\"answer\\\": \\\"meet\\\"\\n  }\\n}\\n\"','2025-05-26 11:28:10','2025-05-26 11:28:10'),(27,5,9,'reorder','\"{\\n  \\\"type\\\": \\\"reorder\\\",\\n  \\\"content\\\": {\\n    \\\"instruction\\\": \\\"Kelimeleri doğru sıraya koyarak yaş sorma cümlesini oluştur.\\\",\\n    \\\"words\\\": [\\\"old\\\", \\\"you\\\", \\\"are\\\", \\\"How\\\", \\\"?\\\"],\\n    \\\"correctOrder\\\": [\\\"How\\\", \\\"old\\\", \\\"are\\\", \\\"you\\\", \\\"?\\\"]\\n  }\\n}\"','2025-05-26 11:29:03','2025-05-26 11:29:03'),(29,5,10,'info','\"{\\n  \\\"type\\\": \\\"info\\\",\\n  \\\"content\\\": {\\n    \\\"title\\\": \\\"Tanışma Kalıpları Hakkında\\\",\\n    \\\"body\\\": \\\"İngilizce\'de tanışma sırasında kullanılan ifadeler, karşılıklı iletişimin temelini oluşturur. Bu kalıplar, bir kişinin adını, yaşını, memleketini sormak ve kendini tanıtmak için kullanılır.\\\\n\\\\nİşte bazı yaygın tanışma kalıpları:\\\\n\\\\n- What\'s your name? → Adın ne?\\\\n- My name is ... → Benim adım ...\\\\n- Nice to meet you. → Tanıştığıma memnun oldum.\\\\n- How old are you? → Kaç yaşındasın?\\\\n- I’m ... years old. → ... yaşındayım.\\\\n- Where are you from? → Nerelisin?\\\\n- I’m from ... → ...’liyim.\\\\n\\\\nBu ifadeler günlük konuşmalarda çok sık kullanılır. İlk tanışmalarda karşınızdaki kişiyle samimi bir diyalog kurmanızı sağlar.\\\",\\n    \\\"imageUrl\\\": \\\"/images/introduction.png\\\",\\n    \\\"imageClass\\\": \\\"max-w-[500px]\\\"\\n  }\\n}\"','2025-05-26 11:36:35','2025-05-26 11:36:35'),(30,5,11,'listen','\"{\\n  \\\"type\\\": \\\"listen\\\",\\n  \\\"content\\\": {\\n    \\\"audioUrl\\\": \\\"/audio/nicetomeetyou.mp3\\\",\\n    \\\"question\\\": \\\"Dinlediğin ifade hangisidir?\\\",\\n    \\\"options\\\": [\\\"Nice to meet you\\\", \\\"How are you\\\", \\\"My name is Alex\\\", \\\"Where are you from\\\"],\\n    \\\"correctAnswer\\\": \\\"Nice to meet you\\\"\\n  }\\n}\"','2025-05-26 11:39:59','2025-05-26 11:39:59'),(31,5,12,'drag-drop','\"{\\n  \\\"type\\\": \\\"drag-drop\\\",\\n  \\\"content\\\": {\\n    \\\"instruction\\\": \\\"İngilizce ifadeleri doğru Türkçe anlamlarıyla eşleştir.\\\",\\n    \\\"pairs\\\": [\\n      { \\\"drag\\\": \\\"What\'s your name?\\\", \\\"drop\\\": \\\"Adın ne?\\\" },\\n      { \\\"drag\\\": \\\"I\'m from Turkey.\\\", \\\"drop\\\": \\\"Türkiye\'denim.\\\" },\\n      { \\\"drag\\\": \\\"Nice to meet you.\\\", \\\"drop\\\": \\\"Tanıştığımıza memnun oldum.\\\" },\\n      { \\\"drag\\\": \\\"How old are you?\\\", \\\"drop\\\": \\\"Kaç yaşındasın?\\\" }\\n    ]\\n  }\\n}\"','2025-05-26 11:41:54','2025-05-26 11:41:54'),(32,5,13,'mcq','\"{\\n  \\\"type\\\": \\\"mcq\\\",\\n  \\\"content\\\": {\\n    \\\"question\\\": \\\"Where are you from? ifadesinin Türkçesi nedir?\\\",\\n    \\\"options\\\": [\\\"Nasılsın?\\\", \\\"Adın ne?\\\", \\\"Nerelisin?\\\", \\\"Ne iş yapıyorsun?\\\"],\\n    \\\"correctAnswer\\\": \\\"Nerelisin?\\\"\\n  }\\n}\"','2025-05-26 11:45:56','2025-05-26 11:45:56'),(33,5,14,'listen','\"{\\n  \\\"type\\\": \\\"listen\\\",\\n  \\\"content\\\": {\\n    \\\"audioUrl\\\": \\\"/audio/whereareyoufrom.mp3\\\",\\n    \\\"question\\\": \\\"Dinlediğin cümle hangisidir?\\\",\\n    \\\"options\\\": [\\n      \\\"Where are you from?\\\",\\n      \\\"What’s your name?\\\",\\n      \\\"How old are you?\\\",\\n      \\\"Nice to meet you.\\\"\\n    ],\\n    \\\"correctAnswer\\\": \\\"Where are you from?\\\"\\n  }\\n}\"','2025-05-26 11:50:18','2025-05-26 11:50:18'),(34,5,15,'reorder','\"{\\n  \\\"type\\\": \\\"reorder\\\",\\n  \\\"content\\\": {\\n    \\\"instruction\\\": \\\"Kelimeleri doğru sıraya koyarak anlamlı bir cümle oluştur.\\\",\\n    \\\"words\\\": [\\\"has\\\", \\\"It\\\", \\\"a\\\", \\\"pleasure\\\", \\\"meeting\\\", \\\"you\\\", \\\"been\\\"],\\n    \\\"correctOrder\\\": [\\\"It\\\", \\\"has\\\", \\\"been\\\", \\\"a\\\", \\\"pleasure\\\", \\\"meeting\\\", \\\"you\\\"]\\n  }\\n}\"','2025-05-26 11:52:07','2025-05-26 11:52:07'),(35,5,16,'drag-drop','\"{\\n  \\\"type\\\": \\\"drag-drop\\\",\\n  \\\"content\\\": {\\n    \\\"instruction\\\": \\\"Aşağıdaki İngilizce ifadeleri Türkçe anlamlarıyla eşleştir.\\\",\\n    \\\"pairs\\\": [\\n      { \\\"drag\\\": \\\"Good to see you again.\\\", \\\"drop\\\": \\\"Seni tekrar görmek güzel.\\\" },\\n      { \\\"drag\\\": \\\"Long time no see!\\\", \\\"drop\\\": \\\"Görüşmeyeli uzun zaman oldu!\\\" },\\n      { \\\"drag\\\": \\\"How’s it going?\\\", \\\"drop\\\": \\\"Nasıl gidiyor?\\\" },\\n      { \\\"drag\\\": \\\"Pleased to meet you.\\\", \\\"drop\\\": \\\"Sizinle tanıştığıma memnun oldum.\\\" }\\n    ]\\n  }\\n}\"','2025-05-26 11:55:19','2025-05-26 11:55:19'),(36,6,1,'info','\"{\\n  \\\"type\\\": \\\"info\\\",\\n  \\\"content\\\": {\\n    \\\"title\\\": \\\"İngilizce Zamirlere Giriş\\\",\\n    \\\"body\\\": \\\"İngilizce\'de zamirler (pronouns), bir ismin yerine kullanılan ve iletişimi daha etkili hale getiren kelimelerdir. Zamirler tekrarı önler, anlamı netleştirir ve cümleleri sadeleştirir.\\\",\\n    \\\"imageUrl\\\": \\\"/images/pronouns.png\\\",\\n    \\\"imageClass\\\": \\\"max-w-[500px] mx-auto\\\"\\n  }\\n}\"','2025-05-26 12:14:13','2025-05-26 12:14:13'),(39,6,4,'fill','\"{\\n  \\\"type\\\": \\\"fill\\\",\\n  \\\"content\\\": {\\n    \\\"sentence\\\": \\\"John is a doctor. ___ works at a hospital.\\\",\\n    \\\"answer\\\": \\\"He\\\"\\n  }\\n}\"','2025-05-26 12:16:51','2025-05-26 12:16:51'),(40,6,5,'mcq','\"{\\n  \\\"type\\\": \\\"mcq\\\",\\n  \\\"content\\\": {\\n    \\\"question\\\": \\\"\'We\' kelimesi hangi zamir türüne aittir?\\\",\\n    \\\"options\\\": [\\\"Object pronoun\\\", \\\"Subject pronoun\\\", \\\"Possessive pronoun\\\", \\\"Reflexive pronoun\\\"],\\n    \\\"correctAnswer\\\": \\\"Subject pronoun\\\"\\n  }\\n}\"','2025-05-26 12:17:58','2025-05-26 12:17:58'),(41,6,6,'listen','\"{\\n  \\\"type\\\": \\\"listen\\\",\\n  \\\"content\\\": {\\n    \\\"audioUrl\\\": \\\"/audio/theyareplayingsoccer.mp3\\\",\\n    \\\"question\\\": \\\"Dinlediğiniz cümlede hangi zamir geçiyor?\\\",\\n    \\\"options\\\": [\\\"They\\\", \\\"We\\\", \\\"He\\\", \\\"It\\\"],\\n    \\\"correctAnswer\\\": \\\"They\\\"\\n  }\\n}\\n\"','2025-05-26 12:19:10','2025-05-26 12:19:10'),(42,6,7,'reorder','\"{\\n  \\\"type\\\": \\\"reorder\\