INSERT INTO `lessons` VALUES (5,'A1 - Alfabe, Selamlaşma ve Tanışma','İngilizce alfabeyi öğren, temel selamlaşmaları ve tanışma ifadelerini kullanmaya başla.','\"A1 - Alfabe, Selamlaşma ve Tanışma\"','A1',NULL,1,'2025-05-26 10:07:03','2025-05-26 10:07:03'),(6,'A1 - Zamirler','İngilizce\'de zamirlerin (pronouns) tanımını, türlerini ve doğru kullanımını interaktif etkinliklerle öğrenin.','\"İngilizce\'de zamirlerin (pronouns) tanımını, türlerini ve doğru kullanımını interaktif etkinliklerle öğrenin.\"','A1',NULL,1,'2025-05-26 12:13:02','2025-05-26 12:13:02'),(7,'A1- Yiyecekler ve İçecekler','İngilizce yiyecekler ve içecekler hakkında kelime bilgisi öğrenin','\"İngilizce yiyecekler ve içecekler kelime bilgisi öğrenin\"','A1',NULL,1,'2025-05-26 12:47:19','2025-05-26 12:54:03');
