INSERT INTO `quizquestions` VALUES (4,3,'Which letter comes after \"D\"?','[\"C\", \"E\", \"F\", \"G\"]','E','2025-05-26 13:27:30','2025-05-26 13:27:30','alphabet'),(5,3,'How do you say “Merhaba” in English?','[\"Goodbye\", \"Thanks\", \"Hello\", \"Please\"]','Hello','2025-05-26 13:27:59','2025-05-26 13:27:59','greetings'),(6,3,'What do you say when someone says “Nice to meet you”?','[\"I’m fine, thanks\", \"Me too\", \"Nice to meet you too\", \"See you\"]','Nice to meet you too','2025-05-26 13:28:27','2025-05-26 13:28:27','greetings'),(7,3,'What is the correct response to “How are you?”','[\"My name is Ayşe\", \"I’m fine, thank you\", \"I live in Ankara\", \"Yes, please\"]','I’m fine, thank you','2025-05-26 13:28:57','2025-05-26 13:28:57','greetings'),(8,3,'What does “Good evening” mean?','[\"Günaydın\", \"İyi akşamlar\", \"İyi geceler\", \"Merhaba\"]','İyi akşamlar','2025-05-26 13:29:25','2025-05-26 13:29:25','greetings'),(9,3,'Which of these is a vowel letter?','[\"M\", \"T\", \"A\", \"R\"]','A','2025-05-26 13:29:50','2025-05-26 13:29:50','alphabet'),(10,3,'What is the English of “Benim adım Ali”?','[\"I am Ali\", \"Ali is name me\", \"I have name Ali\", \"My name is Ali\"]','My name is Ali','2025-05-26 13:30:16','2025-05-26 13:30:16','introductions'),(11,3,'What is the correct order for this question: name / is / your / what?','[\"What your name is?\", \"What is your name?\", \"Is what your name?\", \"Your name what is?\"]','What is your name?','2025-05-26 13:30:39','2025-05-26 13:30:39','sentence_structure'),(12,3,'Which of these is a greeting?','[\"Goodbye\", \"Thanks\", \"Hello\", \"Sorry\"]','Hello','2025-05-26 13:31:04','2025-05-26 13:31:04','greetings'),(13,3,'How do you introduce yourself in English?','[\"I from Turkey\", \"I name is Ayşe\", \"I’m Ayşe\", \"Name Ayşe\"]','I’m Ayşe','2025-05-26 13:31:37','2025-05-26 13:31:37','introductions'),(14,4,'Which one is a subject pronoun?','[\"Him\", \"I\", \"Me\", \"His\"]','I','2025-05-26 13:34:15','2025-05-26 13:34:15','pronouns'),(15,4,'What is the object pronoun of “she”?','[\"Her\", \"Hers\", \"She\", \"Herself\"]','Her','2025-05-26 13:34:38','2025-05-26 13:34:38','pronouns'),(16,4,'“This is ___ book.” Which pronoun completes the sentence?','[\"me\", \"my\", \"mine\", \"I\"]','my','2025-05-26 13:34:58','2025-05-26 13:34:58','pronouns'),(17,4,'Which of the following is a possessive pronoun?','[\"them\", \"us\", \"yours\", \"her\"]','yours','2025-05-26 13:35:24','2025-05-26 13:35:24','pronouns'),(18,4,'“We” is used for:','[\"One person\", \"A group\", \"A place\", \"A thing\"]','A group','2025-05-26 13:35:54','2025-05-26 13:35:54','pronouns'),(19,4,'Which sentence uses “they” correctly?','[\"They is my friend.\", \"They are students.\", \"They am happy.\", \"They be nice.\"]','They are students.','2025-05-26 13:36:15','2025-05-26 13:36:15','pronouns'),(20,4,'Choose the reflexive pronoun:','[\"myself\", \"me\", \"I\", \"mine\"]','myself','2025-05-26 13:36:34','2025-05-26 13:36:34','pronouns'),(21,4,'“___ is my sister. Her name is Mary.”','[\"He\", \"She\", \"Her\", \"Hers\"]','She','2025-05-26 13:36:53','2025-05-26 13:36:53','pronouns'),(22,4,'What is the subject pronoun of “Tom and I”?','[\"We\", \"Us\", \"They\", \"He\"]','We','2025-05-26 13:37:12','2025-05-26 13:37:12','pronouns'),(23,4,'Which one is an object pronoun?','[\"Their\", \"Ours\", \"Them\", \"Yours\"]','Them','2025-05-26 13:37:35','2025-05-26 13:37:35','pronouns'),(24,5,'Which one is a fruit?','[\"Carrot\", \"Apple\", \"Bread\", \"Rice\"]','Apple','2025-05-26 13:39:27','2025-05-26 13:39:27','food'),(25,5,'What do you drink in the morning?','[\"Soup\", \"Coffee\", \"Rice\", \"Bread\"]','Coffee','2025-05-26 13:39:46','2025-05-26 13:39:46','food_and_drinks'),(26,5,'“Fish” is a type of:','[\"Vegetable\", \"Dessert\", \"Meat\", \"Drink\"]','Meat','2025-05-26 13:40:08','2025-05-26 13:40:08','food'),(27,5,'Which of these is a dairy product?','[\"Cheese\", \"Banana\", \"Chicken\", \"Juice\"]','Cheese','2025-05-26 13:40:27','2025-05-26 13:40:27','food'),(28,5,'What is the English of “Ekmek”?','[\"Egg\", \"Bread\", \"Meat\", \"Cake\"]','Bread','2025-05-26 13:40:48','2025-05-26 13:40:48','food'),(29,5,'What do you eat for dessert?','[\"Cake\", \"Fish\", \"Cheese\", \"Sandwich\"]','Cake','2025-05-26 13:41:08','2025-05-26 13:41:08','food'),(30,5,'Which one is a vegetable?','[\"Tomato\", \"Orange\", \"Yogurt\", \"Butter\"]','Tomato','2025-05-26 13:41:26','2025-05-26 13:41:26','food'),(31,5,'“Watermelon” is:','[\"A drink\", \"A vegetable\", \"A fruit\", \"A dessert\"]','A fruit','2025-05-26 13:41:49','2025-05-26 13:41:49','food'),(32,5,'Which one is cold and sweet?','[\"Ice cream\", \"Bread\", \"Cheese\", \"Egg\"]','Ice cream','2025-05-26 13:42:16','2025-05-26 13:42:16','food'),(33,5,'What is the English word for “Süt”?','[\"Salt\", \"Meat\", \"Milk\", \"Tea\"]','Milk','2025-05-26 13:42:38','2025-05-26 13:42:38','food');
